scwin.f_ZrStr = function(str, len) {
	    var j = 0, i =0;
	    var tmp = new Array(len);
	    j = str.length - 1 ;
	    for ( i=(len-1); i >= 0;  i-- ) {
	        if ((len - str.length)  > i) {
	           tmp[i] =  '0';
	        }
	        else {
	           tmp[i] = str.charAt(j--);
	 		}
	    }
	    return tmp.join('');

}

